class Solution:
    def countComponents(self, nums, threshold):
        # independent re-derivation: brute-force pairwise lcm check, correct but
        # only intended for small inputs
        from math import gcd
        n = len(nums)
        parent = list(range(n))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b):
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb
        for i in range(n):
            for j in range(i + 1, n):
                lcm = nums[i] * nums[j] // gcd(nums[i], nums[j])
                if lcm <= threshold:
                    union(i, j)
        return len({find(i) for i in range(n)})

