class Solution:
    def countComponents(self, nums, threshold):
        n = len(nums)
        idx_of = {}
        small = []
        isolated = 0
        for i, v in enumerate(nums):
            if v > threshold:
                isolated += 1
            else:
                idx_of[v] = i
                small.append(v)
        parent = list(range(n))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b):
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb
        rep = [0] * (threshold + 1)
        for v in small:
            d = v
            while d <= threshold:
                if rep[d] == 0:
                    rep[d] = v
                else:
                    union(idx_of[v], idx_of[rep[d]])
                d += v
        roots = {find(idx_of[v]) for v in small}
        return isolated + len(roots)

