var countComponents = function(nums, threshold) {
    const n = nums.length;
    const parent = new Array(n);
    for (let i = 0; i < n; i++) parent[i] = i;
    function find(x) { while (parent[x] !== x) { parent[x] = parent[parent[x]]; x = parent[x]; } return x; }
    function union(a, b) { const ra = find(a), rb = find(b); if (ra !== rb) parent[ra] = rb; }
    const idxOf = new Map();
    const small = [];
    let isolated = 0;
    for (let i = 0; i < n; i++) {
        const v = nums[i];
        if (v > threshold) { isolated++; }
        else { idxOf.set(v, i); small.push(v); }
    }
    const rep = new Array(threshold + 1).fill(0);
    for (const v of small) {
        for (let d = v; d <= threshold; d += v) {
            if (rep[d] === 0) rep[d] = v;
            else union(idxOf.get(v), idxOf.get(rep[d]));
        }
    }
    const roots = new Set();
    for (const v of small) roots.add(find(idxOf.get(v)));
    return isolated + roots.size;
};
